SELECT 
FROM sas_project_spec


        AND username = #{username}


        AND project_id = #{projectId}


        AND domain = #{domain}


        AND variable LIKE CONCAT('%', #{variable}, '%')


        AND label LIKE CONCAT('%', #{label}, '%')


        AND type = #{type}


        AND origin = #{origin}


        AND role = #{role}


        AND core = #{core}


ORDER BY domain ASC, sort_order ASC

    LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM sas_project_spec


        AND username = #{username}


        AND project_id = #{projectId}


        AND domain = #{domain}


        AND variable LIKE CONCAT('%', #{variable}, '%')


        AND label LIKE CONCAT('%', #{label}, '%')


        AND type = #{type}


        AND origin = #{origin}


        AND role = #{role}


        AND core = #{core}

SELECT COUNT(*)
FROM sas_project_spec 
WHERE project_id = #{projectId} AND domain = #{domain} AND variable = #{variable} AND username = #{username}

SELECT cdisc_submission_value as cdiscValue, GROUP_CONCAT(DISTINCT domain ORDER BY domain) as domains FROM sas_project_spec WHERE cdisc_submission_value IS NOT NULL AND cdisc_submission_value != '' AND cdisc_submission_value != 'NULL'
AND project_id = #{projectId}
AND username = #{username}
GROUP BY cdisc_submission_value ORDER BY cdisc_submission_value
